UPDATE questions
SET status = 'ANSWERED'
WHERE question_id = #{questionId}

UPDATE questions
SET
title = #{title},
content = #{content},
is_public = #{isPublic}
WHERE question_id = #{questionId}

UPDATE questions
SET delete_yn = 'Y'
WHERE question_id = #{questionId}

UPDATE questions
SET status = 'PENDING'
WHERE question_id = #{questionId}
